import React, { useState, useEffect } from 'react';
import { animated, useSpring } from '@react-spring/web';
import { X, MessageCircle, Send, Inbox, ChevronDown } from 'lucide-react';

const NudgePanel = ({ 
  isVisible, 
  onClose, 
  newNudges = [], 
  onNudgeSelect,
  selectedNudgeId 
}) => {
  const [activeTab, setActiveTab] = useState('received');
  const [isMinimized, setIsMinimized] = useState(false);

  // Dados mock para demonstração
  const mockSentNudges = [
    {
      id: 'sent-1',
      recipient: {
        name: 'Sarah Johnson',
        avatar: 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=150',
        status: 'online'
      },
      message: 'Quick sync about the project timeline?',
      timestamp: '2 min ago',
      status: 'pending',
      priority: 'high'
    },
    {
      id: 'sent-2',
      recipient: {
        name: 'Mike Chen',
        avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=150',
        status: 'away'
      },
      message: 'Can we discuss the budget changes?',
      timestamp: '1 hour ago',
      status: 'accepted',
      priority: 'medium'
    }
  ];

  const containerAnimation = useSpring({
    transform: isVisible ? 'translateY(0%)' : 'translateY(100%)',
    opacity: isVisible ? 1 : 0,
    height: isMinimized ? '60px' : '500px',
    config: { tension: 300, friction: 30 }
  });

  const unreadCount = newNudges.filter(nudge => !nudge.isRead).length;

  if (!isVisible) return null;

  return (
    <div className="fixed bottom-6 right-6 z-50">
      <animated.div
        style={{
          ...containerAnimation,
          width: '380px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-2xl overflow-hidden"
      >
        {/* Header */}
        <div className="bg-neutral-900 px-4 py-3 border-b border-neutral-700">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <MessageCircle className="h-5 w-5 text-white" />
              <h2 className="text-lg font-semibold text-white">Nudges</h2>
              {unreadCount > 0 && (
                <div className="w-6 h-6 bg-red-500 rounded-full flex items-center justify-center">
                  <span className="text-white text-xs font-bold">{unreadCount}</span>
                </div>
              )}
            </div>
            <div className="flex items-center space-x-2">
              <button
                onClick={() => setIsMinimized(!isMinimized)}
                className="p-1 text-gray-400 hover:text-white transition-colors"
              >
                <ChevronDown className={`h-4 w-4 transition-transform ${isMinimized ? 'rotate-180' : ''}`} />
              </button>
              <button
                onClick={onClose}
                className="p-1 text-gray-400 hover:text-white transition-colors"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
          </div>
        </div>

        {!isMinimized && (
          <>
            {/* Tabs */}
            <div className="flex border-b border-neutral-700">
              <button
                onClick={() => setActiveTab('received')}
                className={`flex-1 px-4 py-3 text-sm font-medium transition-colors ${
                  activeTab === 'received'
                    ? 'text-white bg-neutral-700 border-b-2 border-white'
                    : 'text-neutral-400 hover:text-white'
                }`}
              >
                <div className="flex items-center justify-center space-x-2">
                  <Inbox className="h-4 w-4" />
                  <span>Received</span>
                  {unreadCount > 0 && (
                    <div className="w-5 h-5 bg-red-500 rounded-full flex items-center justify-center">
                      <span className="text-white text-xs font-bold">{unreadCount}</span>
                    </div>
                  )}
                </div>
              </button>
              <button
                onClick={() => setActiveTab('sent')}
                className={`flex-1 px-4 py-3 text-sm font-medium transition-colors ${
                  activeTab === 'sent'
                    ? 'text-white bg-neutral-700 border-b-2 border-white'
                    : 'text-neutral-400 hover:text-white'
                }`}
              >
                <div className="flex items-center justify-center space-x-2">
                  <Send className="h-4 w-4" />
                  <span>Sent</span>
                </div>
              </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto max-h-96">
              {activeTab === 'received' ? (
                <div className="p-2">
                  {newNudges.length > 0 ? (
                    newNudges.map((nudge) => (
                      <div
                        key={nudge.id}
                        onClick={() => onNudgeSelect(nudge)}
                        className={`p-3 rounded-lg cursor-pointer transition-colors mb-2 ${
                          selectedNudgeId === nudge.id
                            ? 'bg-neutral-600 border border-neutral-500'
                            : 'hover:bg-neutral-700'
                        } ${!nudge.isRead ? 'bg-neutral-700' : ''}`}
                      >
                        <div className="flex items-start space-x-3">
                          <div className="relative">
                            <img
                              src={nudge.sender.avatar}
                              alt={nudge.sender.name}
                              className="w-10 h-10 rounded-full"
                            />
                            <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                              nudge.sender.status === 'online' ? 'bg-green-500' : 
                              nudge.sender.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                            }`} />
                            {!nudge.isRead && (
                              <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full" />
                            )}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between">
                              <h3 className={`font-medium truncate ${!nudge.isRead ? 'text-white' : 'text-neutral-300'}`}>
                                {nudge.sender.name}
                              </h3>
                              <span className="text-xs text-neutral-400">{nudge.timestamp}</span>
                            </div>
                            <p className={`text-sm truncate ${!nudge.isRead ? 'text-neutral-200' : 'text-neutral-400'}`}>
                              {nudge.message}
                            </p>
                            {nudge.priority === 'high' && (
                              <div className="mt-1">
                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800">
                                  High Priority
                                </span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8">
                      <Inbox className="h-12 w-12 text-neutral-600 mx-auto mb-3" />
                      <p className="text-neutral-400">No received nudges</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="p-2">
                  {mockSentNudges.map((nudge) => (
                    <div
                      key={nudge.id}
                      onClick={() => onNudgeSelect(nudge)}
                      className={`p-3 rounded-lg cursor-pointer transition-colors mb-2 ${
                        selectedNudgeId === nudge.id
                          ? 'bg-neutral-600 border border-neutral-500'
                          : 'hover:bg-neutral-700'
                      }`}
                    >
                      <div className="flex items-start space-x-3">
                        <div className="relative">
                          <img
                            src={nudge.recipient.avatar}
                            alt={nudge.recipient.name}
                            className="w-10 h-10 rounded-full"
                          />
                          <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                            nudge.recipient.status === 'online' ? 'bg-green-500' : 
                            nudge.recipient.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                          }`} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center justify-between">
                            <h3 className="font-medium text-neutral-300 truncate">
                              {nudge.recipient.name}
                            </h3>
                            <div className="flex items-center space-x-2">
                              <span className="text-xs text-neutral-400">{nudge.timestamp}</span>
                              <div className={`w-2 h-2 rounded-full ${
                                nudge.status === 'pending' ? 'bg-yellow-500' :
                                nudge.status === 'accepted' ? 'bg-green-500' :
                                nudge.status === 'declined' ? 'bg-red-500' : 'bg-gray-500'
                              }`} />
                            </div>
                          </div>
                          <p className="text-sm text-neutral-400 truncate">
                            {nudge.message}
                          </p>
                          {nudge.priority === 'high' && (
                            <div className="mt-1">
                              <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800">
                                High Priority
                              </span>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}
      </animated.div>
    </div>
  );
};

export default NudgePanel;
